assert!(!is_gated_tool("web_search"));
```

crates/arawn-types/src/hooks.rs.doc_comment:
A single hook action (Claude Code format).

# Examples

```rust,ignore
use arawn_types::{HookAction, HookType};

let action = HookAction {
hook_type: HookType::Command,
command: Some("./lint.sh".into()),
prompt: None,
agent: None,
timeout: Some(5000),
};
assert_eq!(action.hook_type, HookType::Command);
```

The root hooks.json structure (Claude Code format).

# Examples

```rust,ignore
use arawn_types::HooksConfig;

let config = HooksConfig::default();
assert!(config.is_empty());

let json = r#"{"hooks":{"PreToolUse":[{"hooks":[{"command":"./check.sh"}]}]}}"#;
let config: HooksConfig = serde_json::from_str(json).unwrap();
assert!(!config.is_empty());
```

crates/arawn-types/src/secret_resolver.r.doc_comment:
Extract a secret name from a handle string, if it matches the pattern.

Returns `Some("github_token")` for `${{secrets.github_token}}`,
`None` for non-matching strings.

# Examples

```rust,ignore
use arawn_types::extract_secret_name;

assert_eq!(extract_secret_name("${{secrets.api_key}}"), Some("api_key"));
assert_eq!(extract_secret_name("plain text"), None);
```

Resolve all `${{secrets.*}}` handles in a string using the given resolver.

Returns the string with all handles replaced by their values.
Unresolved handles are left as-is (the tool will see them and can report an error).

# Examples

```rust,ignore
use arawn_types::resolve_handles_in_string;

let resolved = resolve_handles_in_string(
"Bearer ${{secrets.token}}",
&my_resolver,
);
// If "token" resolves to "abc123": "Bearer abc123"
```

crates/arawn-workstream/src/directory/ma.doc_comment:
Manages the convention-based directory structure for workstreams and sessions.

This struct is `Send + Sync` safe (only contains `PathBuf`).

# Example

```no_run
use arawn_workstream::directory::DirectoryManager;

let manager = DirectoryManager::default();
let paths = manager.allowed_paths("my-project", "session-123");
// Returns [~/.arawn/workstreams/my-project/production/, ~/.arawn/workstreams/my-project/work/]

let scratch_paths = manager.allowed_paths("scratch", "session-456");
// Returns [~/.arawn/workstreams/scratch/sessions/session-456/work/]
```

crates/arawn-workstream/src/directory/us.doc_comment:
Calculate disk usage statistics for a workstream.

Returns detailed usage information including:
- Production directory size
- Work directory size
- Per-session breakdown (for scratch workstream only)
- Warnings if thresholds are exceeded

# Arguments

* `workstream` - The workstream name to analyze

# Returns

* `Ok(UsageStats)` with usage breakdown and any warnings
* `Err(DirectoryError::InvalidName)` if the workstream name is invalid
* `Err(DirectoryError::WorkstreamNotFound)` if the workstream doesn't exist

# Example

```no_run
use arawn_workstream::directory::DirectoryManager;

let manager = DirectoryManager::default();
let stats = manager.get_usage("my-blog").unwrap();
println!("Production: {:.2} MB", stats.production_mb());
println!("Work: {:.2} MB", stats.work_mb());
if !stats.warnings.is_empty() {
println!("Warnings: {:?}", stats.warnings);
}
```

